mapper:
/* OPTIONAL: search for edit mode */


    SELECT
        {{detail_columns_sql}}
    FROM {{main_table}} a
    WHERE a.comp_cd = #{login_comp_cd}
      AND {{pk_conditions}}




    INSERT INTO {{main_table}} (
        comp_cd,
        {{insert_columns}},
        firs_reg_pgm_id, firs_reg_dts, firs_reg_user_id, firs_reg_ip,
        fina_reg_pgm_id, fina_reg_dts, fina_reg_user_id, fina_reg_ip
    ) VALUES (
        #{login_comp_cd},
        {{insert_values}},
        #{reg_pgm_id}, now(), #{login_emp_no}, #{login_user_ip},
        #{reg_pgm_id}, now(), #{login_emp_no}, #{login_user_ip}
    )

    ON CONFLICT ({{pk_columns}})
    DO UPDATE SET
        {{update_set_columns}},
        fina_reg_pgm_id = excluded.firs_reg_pgm_id,
        fina_reg_dts = now(),
        fina_reg_user_id = excluded.firs_reg_user_id,
        fina_reg_ip = excluded.firs_reg_ip



/* OPTIONAL: delete block */


    DELETE FROM {{main_table}}
    WHERE comp_cd = #{login_comp_cd}
      AND {{delete_conditions}}
